import { describe, expect, it } from 'vitest';
import { sweepLadder, LADDER, LADDER_SWEEP_VERSION } from './distance-ladder';

describe('distance-ladder', () => {
  it('sweeps every rung and is monotone (closer dominates farther)', () => {
    const sweep = sweepLadder();
    expect(sweep.version).toBe(LADDER_SWEEP_VERSION);
    expect(sweep.rows.length).toBe(LADDER.length);
    expect(sweep.marginMonotoneNonIncreasing).toBe(true);
    expect(sweep.savingMonotoneNonDecreasing).toBe(true);
  });

  it('every rung nearer than the break rung closes (the dominance claim)', () => {
    const sweep = sweepLadder();
    if (sweep.breakRung === null) return; // whole ladder closes
    const breakIdx = sweep.rows.findIndex((r) => r.name === sweep.breakRung);
    expect(breakIdx).toBeGreaterThan(0);
    for (let i = 0; i < breakIdx; i++) {
      expect(sweep.rows[i]!.marginCloses).toBe(true);
    }
    expect(sweep.rows[breakIdx]!.marginCloses).toBe(false);
  });

  it('near rungs close; the interstellar wall does not', () => {
    const sweep = sweepLadder();
    const moon = sweep.rows.find((r) => r.name === 'Moon');
    const proxima = sweep.rows.find((r) => r.name === 'Proxima Centauri');
    expect(moon?.marginCloses).toBe(true);
    expect(proxima?.marginCloses).toBe(false);
  });

  it('teleport saving grows with distance (Mars conjunction > Moon)', () => {
    const sweep = sweepLadder();
    const moon = sweep.rows.find((r) => r.name === 'Moon')!;
    const marsFar = sweep.rows.find((r) => r.name === 'Mars (conjunction)')!;
    expect(marsFar.teleportSavingSec).toBeGreaterThan(moon.teleportSavingSec);
    expect(marsFar.teleportSavingSec).toBeGreaterThan(2000); // > ~33 min round trip
  });
});
